import { useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import "./styles.css";

export default function EmailVerify() {
  const navigate = useNavigate();
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const inputs = useRef([]);

  const handleChange = (val, i) => {
    if (!/^\d*$/.test(val)) return;

    const newOtp = [...otp];
    newOtp[i] = val.slice(-1);
    setOtp(newOtp);

    if (val && i < 5) inputs.current[i + 1].focus();
  };

  const handleVerify = () => {
    if (otp.join("") === "123456") {
      navigate("/success", { state: { type: "email" } });
    } else {
      alert("Invalid Code (use 123456)");
    }
  };

  return (
    <div className="email-wrapper">

      {/* LEFT PANEL */}
      <div className="email-left-panel">
        <div className="logo">LOS</div>

        <h1>Verify Your Email</h1>
        <p>
          Enter the 6-digit verification code sent to your email to continue securely.
        </p>
      </div>

      {/* RIGHT PANEL */}
      <div className="email-right-panel">
        <div className="email-card">

          <h2>Email Verification</h2>

          <p className="subtext">
            We’ve sent a code to <br />
            <span className="highlight purple-text">
              yourmail@example.com
            </span>
          </p>

          <div className="otp-box">
            {otp.map((d, i) => (
              <input
                key={i}
                ref={(el) => (inputs.current[i] = el)}
                value={d}
                onChange={(e) => handleChange(e.target.value, i)}
                maxLength={1}
              />
            ))}
          </div>

          <p className="resend">
            Resend code in <span>00:45</span>
          </p>

          <button className="purple-btn" onClick={handleVerify}>
            Verify Code
          </button>

        </div>
      </div>

    </div>
  );
}
